                  <w:body>
                    <w:p>
                      <w:pPr><w:tabs><w:tab w:val="decimal" w:pos="1440"/></w:tabs></w:pPr>
                      <w:r><w:t>A</w:t><w:tab/><w:t>123</w:t></w:r>
