        TestAssert.Equal(1, placedStory.FloatingDrawings.Single().TextBoxLayout!.TableRows.Count);
        TestAssert.Contains(FormatPdfRgb(((byte)255, (byte)192, (byte)0), "rg"), page.Content);
    }

