            DocxParagraphKeepRules.Empty,
            null)
        {
            InlineReferences =
            [
                new DocxInlineReference("Comment", "1", null, SourceRunIndex: 0, RunChildIndex: 0, TextOffsetInRun: 11)
            ]
        };
        DocxRelatedStory commentStory = new(
