        {
            Revisions =
            [
                new DocxRevisionInfo("Insertion", "1", "Reviewer", "2026-06-01T00:00:00Z", "inserted")
            ]
        };
        DocxRelatedStory commentStory = new(
            "Comment",
            "/word/comments.xml",
            "1",
            [new DocxParagraphElement(CreateDocxLayoutParagraph("Public collision comment", 10d, 12d))],
