                    </wp:inline>
                  </w:drawing>
                </w:r>
                """;
        }

        static string AnchorDrawingXml(string relationshipId, string behindDocumentValue)
        {
            return $$"""
                <w:r>
                  <w:drawing>
                    <wp:anchor distT="0" distB="0" distL="0" distR="0" behindDoc="{{behindDocumentValue}}">
                      <wp:extent cx="914400" cy="914400"/>
